import{_ as t,o as r,c as o,a2 as e}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"完成首笔融资买入","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"getting-started/first-margin-buy.md","filePath":"zh-CN/getting-started/first-margin-buy.md"}'),i={name:"getting-started/first-margin-buy.md"};function n(l,a,s,p,h,g){return r(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="完成首笔融资买入" tabindex="-1">完成首笔融资买入 <a class="header-anchor" href="#完成首笔融资买入" aria-label="Permalink to &quot;完成首笔融资买入&quot;">​</a></h1><p>在本教程结束时，你将使用融资买入了一只港股，并在持仓页面看到因此产生的融资结欠。</p><p>完成这个教程大约需要 <strong>10 分钟</strong>，需要在港股交易时间内操作（周一至周五 09:30–16:00 香港时间）。</p><h2 id="开始前的准备" tabindex="-1">开始前的准备 <a class="header-anchor" href="#开始前的准备" aria-label="Permalink to &quot;开始前的准备&quot;">​</a></h2><p>确认以下三项已就绪：</p><ul><li>长桥账户中有港元现金（至少数千港元）</li><li>已完成过至少一次港股交易（熟悉下单操作）</li><li>当前是港股持续交易时段（09:30–12:00 或 13:00–16:00，香港时间）</li></ul><p>如果还没有买过港股，请先完成<a href="/wiki/getting-started/buy-first-hk-stock">买入第一只港股</a>教程。</p><blockquote><p>长桥账户默认是保证金账户，融资功能已启用，无需额外开通。</p></blockquote><h2 id="第一步-查看你的融资额度" tabindex="-1">第一步：查看你的融资额度 <a class="header-anchor" href="#第一步-查看你的融资额度" aria-label="Permalink to &quot;第一步：查看你的融资额度&quot;">​</a></h2><p>打开长桥 App，点击底部导航的**「资产」**。</p><p>向下找到**「融资状态」**入口并点击。</p><p>你会看到两个关键数字：</p><ul><li><strong>融资额度</strong>：账户最多可借入的资金上限，由存入资产自动评估</li><li><strong>可用融资额度</strong>：当前还能动用的融资金额（= 融资额度 - 已使用）</li></ul><p>记住你的<strong>可用余额</strong>（现金）和<strong>可用融资额度</strong>，接下来会用到。</p><h2 id="第二步-找到目标股票" tabindex="-1">第二步：找到目标股票 <a class="header-anchor" href="#第二步-找到目标股票" aria-label="Permalink to &quot;第二步：找到目标股票&quot;">​</a></h2><p>点击 App 搜索图标，输入你想购买的港股名称或代码。</p><p>这次教程使用**盈富基金（02800）**作为示例——它是追踪恒生指数的 ETF，每手 500 股，适合小额体验融资。你也可以换成自己感兴趣的任何港股。</p><p>进入股票详情页，记下当前的<strong>卖盘价（Ask）</strong>。</p><h2 id="第三步-下单——买入超过现金余额的金额" tabindex="-1">第三步：下单——买入超过现金余额的金额 <a class="header-anchor" href="#第三步-下单——买入超过现金余额的金额" aria-label="Permalink to &quot;第三步：下单——买入超过现金余额的金额&quot;">​</a></h2><p>点击底部**「买入」**按钮，打开交易面板。</p><p>填写订单：</p><ol><li>订单类型：<strong>限价单</strong></li><li>价格：输入当前卖盘价</li><li>数量：填入一个让预估金额<strong>略超过你的现金余额</strong>的手数</li></ol><p>你会看到面板底部显示**「预估所需资金」**。当预估金额超过现金余额时，系统会自动从融资额度中补足差额——这就是融资买入。</p><p>确认方向为<strong>买入</strong>，点击提交，再点击确认。</p><blockquote><p>超出现金余额的部分就是你正在使用的融资金额。</p></blockquote><h2 id="第四步-确认成交" tabindex="-1">第四步：确认成交 <a class="header-anchor" href="#第四步-确认成交" aria-label="Permalink to &quot;第四步：确认成交&quot;">​</a></h2><p>进入<strong>资产 → 订单记录</strong>，等待订单状态变为**「已成交」**。</p><h2 id="第五步-查看融资结欠" tabindex="-1">第五步：查看融资结欠 <a class="header-anchor" href="#第五步-查看融资结欠" aria-label="Permalink to &quot;第五步：查看融资结欠&quot;">​</a></h2><p>订单成交后，回到**「资产」<strong>，点击</strong>「现金」**标签。</p><p>你会看到出现了一笔**「结欠」<strong>或</strong>「融资余额」**——这就是你通过融资借入的金额，显示为负数。</p><p>进入**「融资状态」<strong>，风控状态变为</strong>「中等」**，表示你正在使用融资。</p><blockquote><p>融资利息从 T+2 交收后开始计算；T+2 当天 17:00 前存入等额港元可避免计息。完整规则见<a href="/wiki/margin/interest-rules">融资利息</a>。</p></blockquote><h2 id="确认完成" tabindex="-1">确认完成 <a class="header-anchor" href="#确认完成" aria-label="Permalink to &quot;确认完成&quot;">​</a></h2><p>在持仓页面，你看到了新买入的股票。在现金页面，你看到了因此产生的结欠。这就是融资买入的完整流程。</p><p><strong>恭喜！你已完成第一笔融资买入。</strong></p><hr><ul><li>了解风险：<a href="/wiki/margin/risk-control">账户风控</a> — 安全/中等/预警/危险四级状态说明</li><li>遇到追缴通知：<a href="/wiki/margin/how-to-respond-to-margin-call">如何应对追加保证金通知</a></li></ul>',37)])])}const c=t(i,[["render",n]]);export{u as __pageData,c as default};
